SELECT de.id AS duty_id, de.shift_date, de.shift_type, de.start_time, de.end_time, e.id AS emp_id, e.emp_no, e.name AS emp_name, e.gender, e.age, e.department, e.position, e.phone, hr_latest.heart_rate AS latest_heart_rate, hr_latest.measure_time AS latest_measure_time, hr_latest.status AS heart_rate_status, IFNULL(ahr_stat.abnormal_count, 0) AS abnormal_count, ahr_latest.alert_level AS latest_alert_level, ahr_latest.handle_status AS latest_handle_status FROM duty_employee de INNER JOIN employee e ON de.emp_id = e.id LEFT JOIN ( SELECT hr1.* FROM heart_rate hr1 INNER JOIN ( SELECT emp_id, MAX(measure_time) AS max_time FROM heart_rate GROUP BY emp_id ) hr2 ON hr1.emp_id = hr2.emp_id AND hr1.measure_time = hr2.max_time ) hr_latest ON e.id = hr_latest.emp_id LEFT JOIN ( SELECT emp_id, COUNT(*) AS abnormal_count FROM abnormal_heart_rate GROUP BY emp_id ) ahr_stat ON e.id = ahr_stat.emp_id LEFT JOIN ( SELECT ahr1.* FROM abnormal_heart_rate ahr1 INNER JOIN ( SELECT emp_id, MAX(measure_time) AS max_time FROM abnormal_heart_rate GROUP BY emp_id ) ahr2 ON ahr1.emp_id = ahr2.emp_id AND ahr1.measure_time = ahr2.max_time ) ahr_latest ON e.id = ahr_latest.emp_id
AND de.shift_date = #{shiftDate}
AND de.shift_type = #{shiftType}
AND e.name LIKE CONCAT('%', #{empName}, '%')
AND e.department = #{department}
ORDER BY de.shift_date DESC, de.shift_type, e.emp_no

